private static final int REQ_OPEN_TREE = 1001;

private void openFolderPicker() {
    Intent intent = new Intent(Intent.ACTION_OPEN_DOCUMENT_TREE);
    intent.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION);
    intent.addFlags(Intent.FLAG_GRANT_WRITE_URI_PERMISSION);
    intent.addFlags(Intent.FLAG_GRANT_PERSISTABLE_URI_PERMISSION);
    startActivityForResult(intent, REQ_OPEN_TREE);
}

@Override
protected void onActivityResult(int requestCode, int resultCode, Intent data) {
    super.onActivityResult(requestCode, resultCode, data);

    if (requestCode == REQ_OPEN_TREE && resultCode == RESULT_OK && data != null) {
        Uri treeUri = data.getData();
        if (treeUri == null) return;

        int flags = data.getFlags()
                & (Intent.FLAG_GRANT_READ_URI_PERMISSION | Intent.FLAG_GRANT_WRITE_URI_PERMISSION);
        getContentResolver().takePersistableUriPermission(treeUri, flags);
    }
}

private void collectFileNames(Context context, Uri treeUri, List<String> out) {
    DocumentFile root = DocumentFile.fromTreeUri(context, treeUri);
    if (root == null) return;
    collectFileNames(root, out);
}

private void collectFileNames(DocumentFile dir, List<String> out) {
    if (dir == null || !dir.isDirectory()) return;

    for (DocumentFile child : dir.listFiles()) {
        if (child.isDirectory()) {
            collectFileNames(child, out);
        } else if (child.isFile()) {
            out.add(child.getName());
        }
    }
}

